INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661cc', '花园酒店，是我现在去广州旅游首选的酒店。交通便利。淘金地铁站A口上来左转即是。酒店大堂气派典雅。服务人员态度热情，服务周到。房间干净。酒店博物馆也令人惊艳。在酒店里竟然有这么内容详实、布展精致的博物馆。文创作品也很具特色。', '["https://dimg04.c-ctrip.com/images/0231k12000bcx5erqA2ED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000bcx7ypg0F8C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000bcx7o2p10E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000bcx0vvz1D00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-05', '花园大床房', '大床房', '独自旅行', 111, 4.718498871295094, 0, 0.0, 4, 1.6094379124341005, 9, '["交通便利性", "前台服务", "卫生状况"]'::jsonb, '交通便利性', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '花园酒店，是我现在去广州旅游首选的酒店。交通便利。淘金地铁站A口上来左转即是。酒', '花园酒店，是我现在去广州旅游首选的酒店。交通便利。淘金地铁站A口上来左转即是。酒店大堂气派典雅。服务人员态度热情，服务周到。房间干净。酒店博物馆也令人惊艳。在酒店里竟然有这么内容详实、布展精致的博物馆。文创作品也很具特色。', '2023-06-05', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661cd', '酒店富丽堂皇，设施高档优雅，服务质量五星，特别是前台燕姿女士服务态度非常好，不仅免费升级了房型，适逢中秋还送了一盒花园酒店的月饼??，晚上又送了甜点，早餐在30楼的旋转餐厅用餐，体验不一样的感觉。', '["https://dimg04.c-ctrip.com/images/0234612000ca4fomf3CBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000ca4dksr987F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000ca460grEE25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230v12000ca4f3247D4B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-29', '花园双床房', '双床房', '家庭亲子', 98, 4.59511985013459, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店富丽堂皇，设施高档优雅，服务质量五星，特别是前台燕姿女士服务态度非常好，不仅', '酒店富丽堂皇，设施高档优雅，服务质量五星，特别是前台燕姿女士服务态度非常好，不仅免费升级了房型，适逢中秋还送了一盒花园酒店的月饼??，晚上又送了甜点，早餐在30楼的旋转餐厅用餐，体验不一样的感觉。', '2023-09-29', 5, '前台服务');
