INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661d7', '免费升级套房，服务态度非常好，出行也很方便。自助早餐很丰盛，是一家很有质感的酒店。
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661d8', '这次来广州冲着花园酒店而来.值得非常值的.尽管是老酒店.但不失当年的风采.宾至如归依旧.总机每个人都非常好＜小蔡小林小卢＞.楼层26的王大姐等服务员工作非常认真有叫必应.庭餐厅服务态度好.不足的是房间设施旧了一点(但.我相信下一次光临一定有所改变)早餐还可以.前台工作人员特认真..这次是广交会召开.员工特别忙.但都很好.点赞花园酒店全体员工！.也祝花园酒店万紫千红！', '["https://dimg04.c-ctrip.com/images/0203a12000cf99jhu4149_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0203412000cf99evw76F6_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0200612000cf99fqx0BD2_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0237012000cf8zh3b3B6B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-20', '红棉大床套房', '套房', '独自旅行', 184, 5.220355825078324, 0, 0.0, 119, 4.787491742782046, 8, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '这次来广州冲着花园酒店而来.值得非常值的.尽管是老酒店.但不失当年的风采.宾至如', '这次来广州冲着花园酒店而来.值得非常值的.尽管是老酒店.但不失当年的风采.宾至如归依旧.总机每个人都非常好＜小蔡小林小卢＞.楼层26的王大姐等服务员工作非常认真有叫必应.庭餐厅服务态度好.不足的是房间设施旧了一点(但.我相信下一次光临一定有所改变)早餐还可以.前台工作人员特认真..这次是广交会召开.员工特别忙.但都很好.点赞花园酒店全体员工！.也祝花园酒店万紫千红！', '2023-10-20', 5, '整体满意度');
