INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661ef', '越秀区的广州花园酒店设施完善，性价比高，wifi给力，环境不错，地理位置好，离淘金地铁站非常的近，五号线淘金站a口出来就看见看见广州花园酒店了，在酒店附近逛街啊 吃饭啊什么的都很方便，位置在市中心，房间还不错?
