INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661f2', '酒店送的下午茶 很精致', '["https://dimg04.c-ctrip.com/images/0233t12000bvmmudo8196_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-10', '红棉大床套房', '套房', '家庭亲子', 11, 2.4849066497880004, 0, 0.0, 11, 2.4849066497880004, 3, '["餐饮设施"]'::jsonb, '餐饮设施', NULL, NULL, '未知酒店', '未知地点', '匿名', '酒店送的下午茶 很精致', '酒店送的下午茶 很精致', '2023-08-10', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661f3', '作为广州老牌星级酒店，各类服务还是保持得非常优质，中华传统文化和岭南文化相结合，无一不彰显着文化底蕴。除了可在瀑布餐厅用餐外，还可以选择锦鲤行政酒廊，环境舒适，还有Zoey、Carrie的服务很好，Carrie中午说的很棒。在行政酒廊外有瀑布可观赏，再往里走有很大的庭院，下午茶点心款式也挺多，happy hour的点心款式更为丰富，晚上8点半后会有驻场歌手唱歌。酒店员工服务热情周到，能够及时解决提出的问题，比如客服中心的Carey、前台的Maggie。对于这次入住非常满意，有机会还会选择入住这里。', '["https://dimg04.c-ctrip.com/images/0232212000aqsx8jfEFEA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000aqsxfoy9F2F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000aqt1nlg18B8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-06', '红棉双床套房', '套房', '朋友出游', 251, 5.529429087511423, 0, 0.0, 27, 3.332204510175204, 9, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '作为广州老牌星级酒店，各类服务还是保持得非常优质，中华传统文化和岭南文化相结合，', '作为广州老牌星级酒店，各类服务还是保持得非常优质，中华传统文化和岭南文化相结合，无一不彰显着文化底蕴。除了可在瀑布餐厅用餐外，还可以选择锦鲤行政酒廊，环境舒适，还有Zoey、Carrie的服务很好，Carrie中午说的很棒。在行政酒廊外有瀑布可观赏，再往里走有很大的庭院，下午茶点心款式也挺多，happy hour的点心款式更为丰富，晚上8点半后会有驻场歌手唱歌。酒店员工服务热情周到，能够及时解决提出的问题，比如客服中心的Carey、前台的Maggie。对于这次入住非常满意，有机会还会选择入住这里。', '2023-03-06', 5, '餐饮设施');
