INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661f9', '花园酒店是此行最满意的酒店。后花园很大很美，花园博物馆非常值得参观。桃园馆可以看到酒店正门。荔湾亭早餐很丰富。周围环境好，有利苑酒家广州酒家点都德都在附近，离地铁非常近。下次再去还住这里。', '["https://dimg04.c-ctrip.com/images/0232912000aqijgohF5D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000aqigp4n1421_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000aqvuzzz51D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000aqiiwd001BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000aqikayqAAB0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000aqvuosy076F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000aqwb7lpEDC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000aqw78p1E979_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-07', '花园双床房', '双床房', '家庭亲子', 94, 4.553876891600541, 0, 0.0, 82, 4.418840607796598, 8, '["周边配套", "交通便利性", "整体满意度"]'::jsonb, '周边配套', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店是此行最满意的酒店。后花园很大很美，花园博物馆非常值得参观。桃园馆可以看', '花园酒店是此行最满意的酒店。后花园很大很美，花园博物馆非常值得参观。桃园馆可以看到酒店正门。荔湾亭早餐很丰富。周围环境好，有利苑酒家广州酒家点都德都在附近，离地铁非常近。下次再去还住这里。', '2023-03-07', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b09417661fa', '位于市中心的这家老牌酒店交通很不错，地铁口一点点远就到了，房间干净整洁，遇到的服务员都会主动招呼，彬彬有礼。前台的Betty很nice，根据我的会员等级升级了房间，还详细介绍了各项礼遇，谢谢她，总之很愉快的一次入住体验。', '["https://dimg04.c-ctrip.com/images/0234712000cr5vhys6421_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000cr61x8lB742_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000cr64l7mEA64_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-18', '花园大床房', '大床房', '独自旅行', 110, 4.709530201312334, 0, 0.0, 33, 3.5263605246161616, 8, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '位于市中心的这家老牌酒店交通很不错，地铁口一点点远就到了，房间干净整洁，遇到的服', '位于市中心的这家老牌酒店交通很不错，地铁口一点点远就到了，房间干净整洁，遇到的服务员都会主动招呼，彬彬有礼。前台的Betty很nice，根据我的会员等级升级了房间，还详细介绍了各项礼遇，谢谢她，总之很愉快的一次入住体验。', '2023-12-18', 5, '交通便利性');
