INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766200', '第一次入住花园酒店，给我的感觉就是愉快??入住酒店那天正好是母亲节，前台为我送上了康乃馨??无论环境，设施，服务，卫生都好。大堂的设计、瀑布餐厅给我们惊艳到了。从酒店门口接待到打扫卫生的服务人员都主动问好。前台的小伙（不好意思没仔细看工牌??）耐心周到的为我们做出合理的安排（我订了大床房和双床房）；餐厅的服务会主动引导安排座位；特别是行政酒廊的Katherine主动引导安排座位，耐心周到的提供服务，主动关心我们的需求，仪态优雅大方。给我们全家留下了深刻的印象。下次有机会我还会入住花园酒店??', '["https://dimg04.c-ctrip.com/images/0235h12000b93rnhm37BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000b93nhg3724A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000b93jkj9946D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000b93nbmkF4BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000b93ttlrE302_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000b93mgovB47E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000b93rz2o417D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000b93r1br1844_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000b93hwv181AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-19', '花园大床房', '大床房', '其他', 248, 5.517452896464707, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '第一次入住花园酒店，给我的感觉就是愉快??入住酒店那天正好是母亲节，前台为我送上', '第一次入住花园酒店，给我的感觉就是愉快??入住酒店那天正好是母亲节，前台为我送上了康乃馨??无论环境，设施，服务，卫生都好。大堂的设计、瀑布餐厅给我们惊艳到了。从酒店门口接待到打扫卫生的服务人员都主动问好。前台的小伙（不好意思没仔细看工牌??）耐心周到的为我们做出合理的安排（我订了大床房和双床房）；餐厅的服务会主动引导安排座位；特别是行政酒廊的Katherine主动引导安排座位，耐心周到的提供服务，主动关心我们的需求，仪态优雅大方。给我们全家留下了深刻的印象。下次有机会我还会入住花园酒店??', '2023-05-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766201', '岭南文化，喜欢一个人在文化气息浓厚的环境内转转，品尝了早餐，相对中国人饮食习惯比较适应，推荐入住，体验客房布草的亲肤感。', '["https://dimg04.c-ctrip.com/images/0234412000ap4mtsz735C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000ap4bkgv50F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000ap4inzz5B7B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000ap4hxc6BD9A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000ap4cw1q9C89_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000ap4i5kjC37D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000ap4h9s3CB07_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000ap4cq642FEC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000ap4dzht7BDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-21', '粤韵大床套房', '套房', '商务出差', 60, 4.110873864173311, 0, 0.0, 16, 2.833213344056216, 6, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '岭南文化，喜欢一个人在文化气息浓厚的环境内转转，品尝了早餐，相对中国人饮食习惯比', '岭南文化，喜欢一个人在文化气息浓厚的环境内转转，品尝了早餐，相对中国人饮食习惯比较适应，推荐入住，体验客房布草的亲肤感。', '2023-02-21', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766202', '酒店位置非常好，地铁就在酒店门口，服务也很到位，卫生很干净。不足之处就是酒店房间设施不好，喷淋要站在浴缸里，没有数据线插孔，这个就很无语，酒店瀑布餐厅环境优美，赞一个。还有推荐酒店正门左拐的建设马路上有一家荔银肠粉老店，那里的肠粉非常好吃??，我连续去吃了三天，推荐虾仁韭黄、和招牌三宝肠粉，艇仔粥也很好吃', '["https://dimg04.c-ctrip.com/images/0231t12000anbcn594C0F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000anbujzpCE9B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000anb484f7BD7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000anbxsde72CE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000anbsz5lEB23_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000anb9v5c706F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-02-11', '花园双床房', '双床房', '家庭亲子', 153, 5.0369526024136295, 0, 0.0, 6, 1.9459101490553128, 8, '["房间设施", "交通便利性", "卫生状况"]'::jsonb, '房间设施', '交通便利性', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店位置非常好，地铁就在酒店门口，服务也很到位，卫生很干净。不足之处就是酒店房间', '酒店位置非常好，地铁就在酒店门口，服务也很到位，卫生很干净。不足之处就是酒店房间设施不好，喷淋要站在浴缸里，没有数据线插孔，这个就很无语，酒店瀑布餐厅环境优美，赞一个。还有推荐酒店正门左拐的建设马路上有一家荔银肠粉老店，那里的肠粉非常好吃??，我连续去吃了三天，推荐虾仁韭黄、和招牌三宝肠粉，艇仔粥也很好吃', '2023-02-11', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766203', '老牌酒店，大堂很气派，喜欢前台服务员的粉色长裙制服，很特别。晚上到店升级到了套间，房间重新装修的很有设计感，60多平米超大很舒适。楼下超大面积的花园在全国酒店里都是很奢侈的，打理的也很精致，很喜欢花园酒店，历史悠久但没有被时代淘汰，还是那么经典，下次来广州还会入住。', '["https://dimg04.c-ctrip.com/images/0233x12000ajcyuaj2256_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000ajcyo6xBD55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000ajcyxip3939_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000ajcz9lc4F58_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000ajcy54u0B5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000ajd0g3vD8F5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-29', '城央绿意双床房', '双床房', '家庭亲子', 133, 4.897839799950911, 0, 0.0, 36, 3.610917912644224, 9, '["整体满意度", "房间设施", "公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '老牌酒店，大堂很气派，喜欢前台服务员的粉色长裙制服，很特别。晚上到店升级到了套间', '老牌酒店，大堂很气派，喜欢前台服务员的粉色长裙制服，很特别。晚上到店升级到了套间，房间重新装修的很有设计感，60多平米超大很舒适。楼下超大面积的花园在全国酒店里都是很奢侈的，打理的也很精致，很喜欢花园酒店，历史悠久但没有被时代淘汰，还是那么经典，下次来广州还会入住。', '2023-01-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766204', '酒店很大气，进门就是礼宾部，服务很热情。我们初四中午12点抵达的，排队3分钟，但是办理入住的时候真的耗时太久了，至少15分钟！背了大包站着好累。其余都挺好的！入住很开心！花园很美丽，给女儿带了包鱼食，她喂得很开心，下次来广州还会入住。', '["https://dimg04.c-ctrip.com/images/0235s12000ajiiv473E6F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000ajigm6k8DC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000ajijpx7A7B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000ajigw0aC357_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000ajiisxo805D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000ajig2i63459_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000ajijd0u23BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-01-30', '花园大床房', '大床房', '家庭亲子', 117, 4.770684624465665, 0, 0.0, 27, 3.332204510175204, 7, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店很大气，进门就是礼宾部，服务很热情。我们初四中午12点抵达的，排队3分钟，但', '酒店很大气，进门就是礼宾部，服务很热情。我们初四中午12点抵达的，排队3分钟，但是办理入住的时候真的耗时太久了，至少15分钟！背了大包站着好累。其余都挺好的！入住很开心！花园很美丽，给女儿带了包鱼食，她喂得很开心，下次来广州还会入住。', '2023-01-30', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766205', '在广州出差一直入住花园酒店，这次前台的Tony小哥还给升级了房型，特别感谢。老牌酒店卫生服务都没的说，关键地理位置一流，吃喝出行都是非常方便。体验很棒????', '["https://dimg04.c-ctrip.com/images/0233b12000brczo6a578C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000brczxa93051_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000brczpaw56B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-27', '花园大床房', '大床房', '商务出差', 79, 4.382026634673881, 0, 0.0, 20, 3.044522437723423, 8, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '在广州出差一直入住花园酒店，这次前台的Tony小哥还给升级了房型，特别感谢。老牌', '在广州出差一直入住花园酒店，这次前台的Tony小哥还给升级了房型，特别感谢。老牌酒店卫生服务都没的说，关键地理位置一流，吃喝出行都是非常方便。体验很棒????', '2023-07-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766206', '这家已经开了30多年的老牌酒店不愧是白金五星级的酒店酒店整体面积规模很大但是老旧这个词跟花园酒店完全没有关系开了这么多年的酒店还保持着这么精致典雅高端不愧是新中国的门面说句实话比现在很多的国际五星酒店要高档的多
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766207', '五星级的服务！五星级的早餐！房间三星级快捷酒店的设计布置是硬伤！酒店外一侧建设六马路据了解封闭已经长达一年之久，对酒店也是有很大的影响！', '["https://dimg04.c-ctrip.com/images/0236912000aqvyj5eC213_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000aqvylv7969C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000aqvyfdeE052_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000aqvylvu703A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000aqvyl1z7ABC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000aqvyhnn2B2A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000aqvyl2jAD66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000aqvyho5413B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000aqvyjiiB3BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-03-07', '花园双床房', '双床房', '商务出差', 68, 4.23410650459726, 0, 0.0, 21, 3.091042453358316, 7, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '五星级的服务！五星级的早餐！房间三星级快捷酒店的设计布置是硬伤！酒店外一侧建设六', '五星级的服务！五星级的早餐！房间三星级快捷酒店的设计布置是硬伤！酒店外一侧建设六马路据了解封闭已经长达一年之久，对酒店也是有很大的影响！', '2023-03-07', 3, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766208', '最坑爹的一次体验，房间比较小这个就不说了，最主要是冲着携程推荐美食酒店第一名的名头去的，结果去里面的所谓的米其林入选餐厅那个桃园馆吃饭，四个人没有喝酒点了四菜一汤花费了2878元，菜品贵到离谱，例如一份牛肉粒就12粒价格599还有另外15%服务费，下面铺的全部是石头，每人就吃了三粒塞牙缝都不够，所有菜品还另收15%服务费，味道也就一般般，以后再也不可能去了，最坑爹的餐饮没有之一', '["https://dimg04.c-ctrip.com/images/0232v12000aj0akpz4251_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.7, 1, '2023-01-28', '城央绿意大床房', '大床房', '家庭亲子', 190, 5.25227342804663, 0, 0.0, 3, 1.3862943611198906, 9, '["餐饮设施", "价格合理性", "整体满意度"]'::jsonb, '餐饮设施', '价格合理性', '整体满意度', '未知酒店', '未知地点', '匿名', '最坑爹的一次体验，房间比较小这个就不说了，最主要是冲着携程推荐美食酒店第一名的名', '最坑爹的一次体验，房间比较小这个就不说了，最主要是冲着携程推荐美食酒店第一名的名头去的，结果去里面的所谓的米其林入选餐厅那个桃园馆吃饭，四个人没有喝酒点了四菜一汤花费了2878元，菜品贵到离谱，例如一份牛肉粒就12粒价格599还有另外15%服务费，下面铺的全部是石头，每人就吃了三粒塞牙缝都不够，所有菜品还另收15%服务费，味道也就一般般，以后再也不可能去了，最坑爹的餐饮没有之一', '2023-01-28', 1, '餐饮设施');
