INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176620a', '前台大堂的员工都给人一种宾至如归的感觉，特别是前台带人办理入住的粉色衣服的几个小姐姐们超有礼貌的。
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176620b', '久闻花园酒店大名，由贝聿铭大师设计，***主席奠基，***爷爷题名。这次入住一晚，果然名不虚传。近40年历史沉淀，体系了厚重的岭南文化，酒店内植被茂盛，瀑布飞泄，锦鲤成群。大堂里美女成群，彬彬有礼。餐厅服务也是一流的，我们坐在“船屋”里品尝粤菜，别有一番风味。', '["https://dimg04.c-ctrip.com/images/0205h12000aerltlu0DAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0202112000aerheoxFE31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0200812000aergz8t4C9C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0202k12000aerjb32BB00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-09', '城央绿意大床房', '大床房', '情侣出游', 130, 4.875197323201151, 0, 0.0, 98, 4.59511985013459, 9, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '久闻花园酒店大名，由贝聿铭大师设计，***主席奠基，***爷爷题名。这次入住一晚', '久闻花园酒店大名，由贝聿铭大师设计，***主席奠基，***爷爷题名。这次入住一晚，果然名不虚传。近40年历史沉淀，体系了厚重的岭南文化，酒店内植被茂盛，瀑布飞泄，锦鲤成群。大堂里美女成群，彬彬有礼。餐厅服务也是一流的，我们坐在“船屋”里品尝粤菜，别有一番风味。', '2023-01-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176620c', '酒店交通比较方便，旁边有地铁站口，酒店对面就是广州友谊商场，酒店大厅装饰很有特色，还有瀑布餐厅，服务人员比较热情，客房有点小旧', '["https://dimg04.c-ctrip.com/images/0236p12000aq7j89f750D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000b70enlf2584_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000aq7ghuw2A0B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000b70imfmA84D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000b70ffrs3DF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-05-10', '城央绿意大床房', '大床房', '其他', 63, 4.158883083359672, 0, 0.0, 22, 3.1354942159291497, 7, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '酒店交通比较方便，旁边有地铁站口，酒店对面就是广州友谊商场，酒店大厅装饰很有特色', '酒店交通比较方便，旁边有地铁站口，酒店对面就是广州友谊商场，酒店大厅装饰很有特色，还有瀑布餐厅，服务人员比较热情，客房有点小旧', '2023-05-10', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176620d', '一次非常愉快的入住体验！首先，是登记入住环节，前台的帅哥Joe非常有耐心有礼貌，看到我带着老人和小孩就给了房间升级。酒店地点非常便利，周边出行无论是打车，坐地铁或者走路出去吃饭按摩都很方便。这几天广州非常炎热，懒得出门，所以在酒店吃了几顿饭。两家粤菜馆各有千秋，其中米其林那家的出品真是意外的精品。自助餐厅的菜式虽然款式不多，但味道很不错。让我想起了香港的半岛酒店自助餐，也是菜式特别少，但样样是精品。美中不足是房间内部味道有一点点陈旧，建议增加香薰。公共区域的味道就很好闻。总之，以后去广州还住花园酒店。', '["https://dimg04.c-ctrip.com/images/0231g12000blabj257D22_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000bla1yudB625_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-06', '花园双床房', '双床房', '家庭亲子', 253, 5.537334267018537, 1, 0.6931471805599453, 15, 2.772588722239781, 9, '["前台服务", "交通便利性", "餐饮设施"]'::jsonb, '前台服务', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '一次非常愉快的入住体验！首先，是登记入住环节，前台的帅哥Joe非常有耐心有礼貌，', '一次非常愉快的入住体验！首先，是登记入住环节，前台的帅哥Joe非常有耐心有礼貌，看到我带着老人和小孩就给了房间升级。酒店地点非常便利，周边出行无论是打车，坐地铁或者走路出去吃饭按摩都很方便。这几天广州非常炎热，懒得出门，所以在酒店吃了几顿饭。两家粤菜馆各有千秋，其中米其林那家的出品真是意外的精品。自助餐厅的菜式虽然款式不多，但味道很不错。让我想起了香港的半岛酒店自助餐，也是菜式特别少，但样样是精品。美中不足是房间内部味道有一点点陈旧，建议增加香薰。公共区域的味道就很好闻。总之，以后去广州还住花园酒店。', '2023-07-06', 5, '前台服务');
