INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176620f', '出差很方便', '["https://dimg04.c-ctrip.com/images/023352224vfs8tly81996_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023652215fcf2rhxs9A0B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h2234bj5exneoFD3D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-15', '花园双床房', '双床房', '商务出差', 5, 1.791759469228055, 0, 0.0, 24, 3.218875824868201, 3, '["交通便利性"]'::jsonb, '交通便利性', NULL, NULL, '未知酒店', '未知地点', '匿名', '出差很方便', '出差很方便', '2023-06-15', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766210', '前台Ariel给升级了红棉房。可以算是套房，很大很好，浴缸也很大小孩子可以在里面游泳了，户外泳池非常棒，让我们从北方来的小孩子抓住了夏天的尾巴还能游泳吃冰淇淋，赞服务，贴心到位，退房时间不用多说就延迟到两点，给力（尤其是国庆旺季期间），四楼博物馆也很棒，住店客人随便进，酒店行政酒廊环境很不错，吃的也丰富，还有livemusic表演。大堂很漂亮，也有表演，门口打车很方便，体验妥妥五星', '["https://dimg04.c-ctrip.com/images/0231v12000cb9iaxa49FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000cb995vl427D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000cb977w12B52_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-03', '花园大床房', '大床房', '家庭亲子', 192, 5.262690188904886, 0, 0.0, 8, 2.19722457733622, 9, '["前台服务", "公共设施", "整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '前台Ariel给升级了红棉房。可以算是套房，很大很好，浴缸也很大小孩子可以在里面', '前台Ariel给升级了红棉房。可以算是套房，很大很好，浴缸也很大小孩子可以在里面游泳了，户外泳池非常棒，让我们从北方来的小孩子抓住了夏天的尾巴还能游泳吃冰淇淋，赞服务，贴心到位，退房时间不用多说就延迟到两点，给力（尤其是国庆旺季期间），四楼博物馆也很棒，住店客人随便进，酒店行政酒廊环境很不错，吃的也丰富，还有livemusic表演。大堂很漂亮，也有表演，门口打车很方便，体验妥妥五星', '2023-10-03', 5, '前台服务');
