INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b0941766219', '老牌花园酒店，入住一如既往的喜欢。广州酒店入住，首选还是花园，主要是装修风格服务特别好，附近逛街美食也很方便', '["https://dimg04.c-ctrip.com/images/0235312000arzo8co19C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000arzeab1A253_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000arzdvk00181_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-16', '城央绿意大床房', '大床房', '独自旅行', 54, 4.007333185232471, 0, 0.0, 54, 4.007333185232471, 7, '["整体满意度", "前台服务", "周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '老牌花园酒店，入住一如既往的喜欢。广州酒店入住，首选还是花园，主要是装修风格服务', '老牌花园酒店，入住一如既往的喜欢。广州酒店入住，首选还是花园，主要是装修风格服务特别好，附近逛街美食也很方便', '2023-03-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028542e3c98b094176621a', '每个接触的服务员都非常nice， 中午来早了，前台办理入住时，得到小妹妹各种温馨介绍，还免费升级粤韵房型，一房一厅，房和厅一样大那种，两个大电视，一键升降窗帘，住的很舒服。客房服务员罗伟星服务热情，对提出的要求都能一一满足，打扫很仔细，处处为客人考虑，值得表扬。博物馆也看了，26个打卡点也人工导览了，带看很仔细，酒店的来龙去脉也清楚了，很棒。早餐看起来不是很多，但吃起来啥都有。周边地铁施工，但窗都是中空玻璃，隔音效果还是比较好的，下次会再入住的。', '["https://dimg04.c-ctrip.com/images/0231912000c4au16b18EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000c4ayfqq49F4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-13', '花园大床房', '大床房', '朋友出游', 225, 5.420534999272286, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "客房服务", "安静程度"]'::jsonb, '前台服务', '客房服务', '安静程度', '未知酒店', '未知地点', '匿名', '每个接触的服务员都非常nice， 中午来早了，前台办理入住时，得到小妹妹各种温馨', '每个接触的服务员都非常nice， 中午来早了，前台办理入住时，得到小妹妹各种温馨介绍，还免费升级粤韵房型，一房一厅，房和厅一样大那种，两个大电视，一键升降窗帘，住的很舒服。客房服务员罗伟星服务热情，对提出的要求都能一一满足，打扫很仔细，处处为客人考虑，值得表扬。博物馆也看了，26个打卡点也人工导览了，带看很仔细，酒店的来龙去脉也清楚了，很棒。早餐看起来不是很多，但吃起来啥都有。周边地铁施工，但窗都是中空玻璃，隔音效果还是比较好的，下次会再入住的。', '2023-09-13', 5, '前台服务');
