INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b0941766223', '12月内两次入住花园大酒店，前台员工专业、热情，第一次入住时就免费升级到高级房，还赠送给我们花园行政酒廊体验，入住期间可以去花园品下午茶、看瀑布、观赏池中的游弋的锦鲤；房间布局设计是我喜欢的风格，干净整洁，床品柔软舒适； 酒店位置优越，酒店外就是地铁站；街对面就是友谊广场，广州酒家、陶陶居、點都德、利苑酒家等都在附近；出行、购物、美食都很方便。 最赞的是：酒店前台、行政酒廊、桃园餐厅、大厅等服务人员都很热情??谢谢，入住期间很愉快！会推荐给亲朋好友，下次来广州花园酒店仍然是我的第一选择！', '["https://dimg04.c-ctrip.com/images/0234r2234awpimjio926C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-19', '花园大床房', '大床房', '家庭亲子', 246, 5.5093883366279774, 0, 0.0, 552, 6.315358001522335, 9, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '12月内两次入住花园大酒店，前台员工专业、热情，第一次入住时就免费升级到高级房，', '12月内两次入住花园大酒店，前台员工专业、热情，第一次入住时就免费升级到高级房，还赠送给我们花园行政酒廊体验，入住期间可以去花园品下午茶、看瀑布、观赏池中的游弋的锦鲤；房间布局设计是我喜欢的风格，干净整洁，床品柔软舒适； 酒店位置优越，酒店外就是地铁站；街对面就是友谊广场，广州酒家、陶陶居、點都德、利苑酒家等都在附近；出行、购物、美食都很方便。 最赞的是：酒店前台、行政酒廊、桃园餐厅、大厅等服务人员都很热情??谢谢，入住期间很愉快！会推荐给亲朋好友，下次来广州花园酒店仍然是我的第一选择！', '2023-04-19', 5, '前台服务');
