INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b094176625a', '酒店文化气息丰富，装饰细节处处彰显，从LILI管家到客房中心小何、行政酒廊服务ECHO，每个服务人员都非常认真可亲，对客人有问必答，事事有回应，件件都落实。我的体验感真是无比亲切！下次还来，提一嘴酒店的博物馆做得很好呢！', '["https://dimg04.c-ctrip.com/images/0235012000f6ibw6qBFAF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000f6ik1pj3A8F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000f6hxp9r6C37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-19', '花园双床房', '双床房', '家庭亲子', 110, 4.709530201312334, 0, 0.0, 11, 2.4849066497880004, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店文化气息丰富，装饰细节处处彰显，从LILI管家到客房中心小何、行政酒廊服务E', '酒店文化气息丰富，装饰细节处处彰显，从LILI管家到客房中心小何、行政酒廊服务ECHO，每个服务人员都非常认真可亲，对客人有问必答，事事有回应，件件都落实。我的体验感真是无比亲切！下次还来，提一嘴酒店的博物馆做得很好呢！', '2024-08-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b0941766271', '特别感谢rain妹妹，特别漂亮的一个小妹妹，每次都是提前准备好，这次是家人过来住，家人对房间很满意，40多年的老店能保持这么好，理地位置也不错，出门就是地铁，还有博物馆，里面还有8个餐厅，都不用出去吃，拍照也是很好看，服务态度那就不用说了，真的很人性化，我个人还是很喜欢的。', '["https://dimg04.c-ctrip.com/images/0235g12000awu8iga17A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000awu8trlFD37_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000awu97021808_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-11', '花园双床房', '双床房', '家庭亲子', 137, 4.927253685157205, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "交通便利性", "周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '特别感谢rain妹妹，特别漂亮的一个小妹妹，每次都是提前准备好，这次是家人过来住', '特别感谢rain妹妹，特别漂亮的一个小妹妹，每次都是提前准备好，这次是家人过来住，家人对房间很满意，40多年的老店能保持这么好，理地位置也不错，出门就是地铁，还有博物馆，里面还有8个餐厅，都不用出去吃，拍照也是很好看，服务态度那就不用说了，真的很人性化，我个人还是很喜欢的。', '2023-04-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b0941766276', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，这个价格入住这个酒店真的是超值，下次有机会一定会再来，停车方便，入住很快，房间也比较舒适，价格不贵，环境也不错，房间干净，入住首选，满意！特别感谢迎宾李文。前台Viria', '["https://dimg04.c-ctrip.com/images/0236x12000jgqv957DDF1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000jgrrk2q150D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-01', '花园大床房', '大床房', '独自旅行', 125, 4.836281906951478, 0, 0.0, 1, 0.6931471805599453, 6, '["整体满意度", "卫生状况", "性价比"]'::jsonb, '整体满意度', '卫生状况', '性价比', '未知酒店', '未知地点', '匿名', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，', '每位酒店的工作人员都非常的热情，让人感觉很舒服，环境也很赞，最主要的是干净卫生，这个价格入住这个酒店真的是超值，下次有机会一定会再来，停车方便，入住很快，房间也比较舒适，价格不贵，环境也不错，房间干净，入住首选，满意！特别感谢迎宾李文。前台Viria', '2025-04-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b094176627d', '酒店被鲜花绿树环绕，大堂富丽堂皇，前台susan微笑服务，操作熟练，办理入住快，安排房间满意。房间亮敞、ROSS打扫房间干净整洁无死角，且服务好。泳池环境好，服务好。瀑布旁吃早餐很惬意，品种繁多，环境好，服务好。参观了四楼博物馆，非常好，很多图片，实物完整了解酒店业的发展，长知识。总机接线员卢小姐，沟通能力强，处理问题暖心。', '["https://dimg04.c-ctrip.com/images/0233m12000cfn2ibtD645_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000cfn0s98C795_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000cfn1yzfEE31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000cfn36mnFB42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000cfn1he13CE4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000cfn1yzhE33C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000cfn0uql9714_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000cfn442z4E80_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000cfn28k8A72C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-22', '红棉大床套房', '套房', '朋友出游', 163, 5.099866427824199, 0, 0.0, 160, 5.081404364984463, 9, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店被鲜花绿树环绕，大堂富丽堂皇，前台susan微笑服务，操作熟练，办理入住快，', '酒店被鲜花绿树环绕，大堂富丽堂皇，前台susan微笑服务，操作熟练，办理入住快，安排房间满意。房间亮敞、ROSS打扫房间干净整洁无死角，且服务好。泳池环境好，服务好。瀑布旁吃早餐很惬意，品种繁多，环境好，服务好。参观了四楼博物馆，非常好，很多图片，实物完整了解酒店业的发展，长知识。总机接线员卢小姐，沟通能力强，处理问题暖心。', '2023-10-22', 5, '前台服务');
