INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b0941766289', '这次入住体验很满意，各方面服务都很好，kamille的服务很棒，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0234312000b8la2ybBBCE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-17', '红棉大床套房', '套房', '商务出差', 39, 3.688879454113936, 0, 0.0, 6, 1.9459101490553128, 5, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '这次入住体验很满意，各方面服务都很好，kamille的服务很棒，下次还会入住。', '这次入住体验很满意，各方面服务都很好，kamille的服务很棒，下次还会入住。', '2023-05-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b094176628a', '房间设施齐全，服务人员素质高，，跟一些快捷商务酒店很不一样。早餐品种丰富，房间设施新，床品舒服，总体物超所值，是一次非常满意的体验。可加床，门口可停车，离多条地铁站近，步行七八分钟。离高铁站机场七八公里。', '["https://dimg04.c-ctrip.com/images/0231g12000app31qt97C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000app227c6327_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000amriw5gD8F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-25', '城央绿意双床房', '双床房', '商务出差', 102, 4.634728988229636, 0, 0.0, 59, 4.0943445622221, 7, '["房间设施", "整体满意度", "交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '房间设施齐全，服务人员素质高，，跟一些快捷商务酒店很不一样。早餐品种丰富，房间设', '房间设施齐全，服务人员素质高，，跟一些快捷商务酒店很不一样。早餐品种丰富，房间设施新，床品舒服，总体物超所值，是一次非常满意的体验。可加床，门口可停车，离多条地铁站近，步行七八分钟。离高铁站机场七八公里。', '2023-02-25', 5, '房间设施');
