INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b094176628e', '房间真的很棒，服务也特别特别好。进来酒店就感觉很大气，前台savanna小姐姐的服务也是超级好！很贴心并且长的很漂亮也很感谢她！冲着她的服务下次来还是会选择这家酒店！很值得！', '["https://dimg04.c-ctrip.com/images/0234412000cnej4af6A9B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000cnehhg8AEA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-28', '红棉大床套房', '套房', '独自旅行', 87, 4.477336814478207, 0, 0.0, 5, 1.791759469228055, 7, '["前台服务", "整体满意度", "性价比"]'::jsonb, '前台服务', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '房间真的很棒，服务也特别特别好。进来酒店就感觉很大气，前台savanna小姐姐的', '房间真的很棒，服务也特别特别好。进来酒店就感觉很大气，前台savanna小姐姐的服务也是超级好！很贴心并且长的很漂亮也很感谢她！冲着她的服务下次来还是会选择这家酒店！很值得！', '2023-11-28', 5, '前台服务');
