INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b0941766292', '花园酒店是我出差广州的必选酒店。位置好。而且最关键的是它的后花园，环境真的超舒服。里头的水池锦鲤，亭宇楼阁。美不胜收。最难得的就是前台服务Betty小姐，服务超好，细致耐心且十分礼貌。是一次绝佳的体验。[强][强][强]', '["https://dimg04.c-ctrip.com/images/0235l12000aqs3tflE845_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000aqsbof3E039_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000aqs9m6b08B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000aqsat7iA4C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000aqs2el78B47_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000aqs4j28A178_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000aqs3j607F19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000aqsbhgz9ABF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000aqs80zq0FA4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-06', '花园大床房', '大床房', '商务出差', 110, 4.709530201312334, 0, 0.0, 26, 3.295836866004329, 8, '["前台服务", "整体满意度", "周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套', '未知酒店', '未知地点', '匿名', '花园酒店是我出差广州的必选酒店。位置好。而且最关键的是它的后花园，环境真的超舒服', '花园酒店是我出差广州的必选酒店。位置好。而且最关键的是它的后花园，环境真的超舒服。里头的水池锦鲤，亭宇楼阁。美不胜收。最难得的就是前台服务Betty小姐，服务超好，细致耐心且十分礼貌。是一次绝佳的体验。[强][强][强]', '2023-03-06', 5, '前台服务');
