INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b094176629e', '过年非常热闹，人很多，服务人员训练有素，有经验的进行询问引导。环境还是这么好，大气又精致，朋友家人来穗首选酒店。热心的前台管家Cathy还送一支漂亮??，非常开心！', '["https://dimg04.c-ctrip.com/images/0230512000ajhul8q3A55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000ajhpq0k2E56_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000ajhu76iB92A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-30', '花园大床房', '大床房', '朋友出游', 82, 4.418840607796598, 0, 0.0, 4, 1.6094379124341005, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '过年非常热闹，人很多，服务人员训练有素，有经验的进行询问引导。环境还是这么好，大', '过年非常热闹，人很多，服务人员训练有素，有经验的进行询问引导。环境还是这么好，大气又精致，朋友家人来穗首选酒店。热心的前台管家Cathy还送一支漂亮??，非常开心！', '2023-01-30', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b094176629f', '位置一流！去哪都不远，附近好吃的很多。
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662a0', '酒店周围郁郁葱葱的花园营造出宁静的氛围，非常适合放松身心。工作人员非常友好和细心，确保满足我们的所有需求。房间宽敞、设备齐全，可欣赏到城市的壮丽景色。酒店内的餐饮选择多样而美味，可满足所有口味。此外，酒店位置便利，方便探索当地景点。我强烈推荐所有来广州的客人入住花园酒店！', '["https://dimg04.c-ctrip.com/images/0236r324x90cnuwqtA87E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-05', '城央绿意大床房', '大床房', '朋友出游', 136, 4.919980925828125, 0, 0.0, 48, 3.8918202981106265, 9, '["整体满意度", "景观/朝向", "餐饮设施"]'::jsonb, '整体满意度', '景观/朝向', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店周围郁郁葱葱的花园营造出宁静的氛围，非常适合放松身心。工作人员非常友好和细心', '酒店周围郁郁葱葱的花园营造出宁静的氛围，非常适合放松身心。工作人员非常友好和细心，确保满足我们的所有需求。房间宽敞、设备齐全，可欣赏到城市的壮丽景色。酒店内的餐饮选择多样而美味，可满足所有口味。此外，酒店位置便利，方便探索当地景点。我强烈推荐所有来广州的客人入住花园酒店！', '2025-04-05', 5, '整体满意度');
