INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662a2', '地方舒适，环境卫生，服务员态度和蔼亲切。往后来广州都住这。', '["https://dimg04.c-ctrip.com/images/0233s224x8yp80qo5EC16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a224x8yp93tp5FF34_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-18', '城央绿意双床房', '双床房', '家庭亲子', 29, 3.4011973816621555, 0, 0.0, 3, 1.3862943611198906, 5, '["整体满意度", "卫生状况", "前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务', '未知酒店', '未知地点', '匿名', '地方舒适，环境卫生，服务员态度和蔼亲切。往后来广州都住这。', '地方舒适，环境卫生，服务员态度和蔼亲切。往后来广州都住这。', '2025-01-18', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662a3', '这次已经是我们的第二十多次入住花园酒店了，酒店的优雅格局和保养依然是很好！而且房间仍然是保持得很好，很卫生和干净 非常的舒适！
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662a9', '酒店出门几百米就有地铁，出行非常方便，早餐有三个餐厅可以选择，30楼的旋转餐厅和1楼的瀑布餐厅以及3楼的桃源馆都很棒，推荐升级套房住会舒服些，在花园酒店可以感受到浓郁的岭南风情与外地文化，还有酒店的博物馆也是很值得打卡的，酒店的工作人员都很nice，但是吧缺点就是隔音不好，入住时遇到楼上亲子家庭的晚上8点开始吵闹蹦蹦跳跳，早上7点半开始蹦蹦跳跳，吵到人怀疑人生的那种就挺无奈的吧！！！！', '["https://dimg04.c-ctrip.com/images/0230512000fgiv5x2D598_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000fgigkre22C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000fgia37n6F70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000fgihdtiC087_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000fgiddxu8668_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000fgif00976A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000fgis8u94983_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000fgih6btB01F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000fgirway3C1C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-08', '花园大床房', '大床房', '朋友出游', 194, 5.272999558563747, 0, 0.0, 5, 1.791759469228055, 9, '["交通便利性", "餐饮设施", "安静程度"]'::jsonb, '交通便利性', '餐饮设施', '安静程度', '未知酒店', '未知地点', '匿名', '酒店出门几百米就有地铁，出行非常方便，早餐有三个餐厅可以选择，30楼的旋转餐厅和', '酒店出门几百米就有地铁，出行非常方便，早餐有三个餐厅可以选择，30楼的旋转餐厅和1楼的瀑布餐厅以及3楼的桃源馆都很棒，推荐升级套房住会舒服些，在花园酒店可以感受到浓郁的岭南风情与外地文化，还有酒店的博物馆也是很值得打卡的，酒店的工作人员都很nice，但是吧缺点就是隔音不好，入住时遇到楼上亲子家庭的晚上8点开始吵闹蹦蹦跳跳，早上7点半开始蹦蹦跳跳，吵到人怀疑人生的那种就挺无奈的吧！！！！', '2024-09-08', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662aa', '环境不错????', '["https://dimg04.c-ctrip.com/images/02321224x90n99g89052D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2025-04-15', '城央绿意双床房', '双床房', '家庭亲子', 8, 2.19722457733622, 0, 0.0, 25, 3.258096538021482, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '环境不错????', '环境不错????', '2025-04-15', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662ab', '这是我们回国第二次入住花园酒店,我们预订了5天；办理入住的前台玲玲负责接待我们,她的服务态度非常好,解释清晰,非常细心,办理入住手续快捷，安排的房间在13楼房间干净整洁,客房部清洁人员非常勤快,每天准时清洁房间卫生，服务态度也是超好的,总体客房部表现不错??
