INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662ad', '在花园酒店住的时光总是很愉快！从家庭服务到非常干净的房间，我一定会再来这里住的！', '["https://dimg04.c-ctrip.com/images/0230v12000eszsk7qBF91_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000eszrcxz3664_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000eszrcy1414D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000eszriq65875_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000eszsepa7CAC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-17', '花园大床房', '大床房', '商务出差', 40, 3.713572066704308, 0, 0.0, 6, 1.9459101490553128, 6, '["整体满意度", "卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '在花园酒店住的时光总是很愉快！从家庭服务到非常干净的房间，我一定会再来这里住的！', '在花园酒店住的时光总是很愉快！从家庭服务到非常干净的房间，我一定会再来这里住的！', '2024-07-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662ae', '20年的同学推荐入住，以为这么历史久远的酒店会各种旧，除了硬件差一点点，洗手台没有分区之外，其他都很好。特别是前台Billy，是我住过所有酒店里面感觉最专业和最有温度的！谢谢你！还有我们入住的21楼楼层负责人小朱很细心入微！服务是真的绝绝子??', '["https://dimg04.c-ctrip.com/images/0235e12000dkl50l3697F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000dkl3cmt99EA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000dkl3cmvD4D9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-03', '花园双床房', '双床房', '家庭亲子', 122, 4.812184355372417, 0, 0.0, 17, 2.8903717578961645, 8, '["前台服务", "客房服务", "房间设施"]'::jsonb, '前台服务', '客房服务', '房间设施', '未知酒店', '未知地点', '匿名', '20年的同学推荐入住，以为这么历史久远的酒店会各种旧，除了硬件差一点点，洗手台没', '20年的同学推荐入住，以为这么历史久远的酒店会各种旧，除了硬件差一点点，洗手台没有分区之外，其他都很好。特别是前台Billy，是我住过所有酒店里面感觉最专业和最有温度的！谢谢你！还有我们入住的21楼楼层负责人小朱很细心入微！服务是真的绝绝子??', '2024-04-03', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662af', '酒店服务很好，连续住了一个星期，升级了大套间，棒棒的！白金五星酒店，果然是与众不同的！
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662b0', '我们很高兴他们为我们的房间升级提供了更好的服务，而且他们干净整洁的客房服务始终是最好的一点。这次我们一家人出游，在同一家酒店住了两天，有两种不同类型的房间，可以品尝到他们的优质服务。特别是他们教我如何使用他们的咖啡机。这样我醒来时就可以品尝咖啡。沐浴区满足了我的愿望，一个浴缸一个淋浴。希望我们能再次来到这里并轻松接种疫苗。再次感谢花园酒店的服务。', '["https://dimg04.c-ctrip.com/images/0234f12000cznhi999532_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000cznlysxFA70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000cznwqmmA91A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000czniwxtE657_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000cznvaiy1410_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-21', '城央绿意大床房', '大床房', '家庭亲子', 174, 5.1647859739235145, 1, 0.6931471805599453, 4, 1.6094379124341005, 7, '["客房服务", "房间设施", "整体满意度"]'::jsonb, '客房服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '我们很高兴他们为我们的房间升级提供了更好的服务，而且他们干净整洁的客房服务始终是', '我们很高兴他们为我们的房间升级提供了更好的服务，而且他们干净整洁的客房服务始终是最好的一点。这次我们一家人出游，在同一家酒店住了两天，有两种不同类型的房间，可以品尝到他们的优质服务。特别是他们教我如何使用他们的咖啡机。这样我醒来时就可以品尝咖啡。沐浴区满足了我的愿望，一个浴缸一个淋浴。希望我们能再次来到这里并轻松接种疫苗。再次感谢花园酒店的服务。', '2024-01-21', 5, '客房服务');
