INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028543e3c98b09417662b2', '第二次来，服务很好，环境清洁，前台小陈专业。酒店的地理位置便利就在淘金上盖。总体很满意。团了套餐包早也送500餐券，等于午餐买一送一。房间升级了新装修的套房，感觉不错，就是有其他房间客人开门抽烟有点讨厌。', '["https://dimg04.c-ctrip.com/images/0233r2215grsurye8A955_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s2215grsust9cF57B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023622234cyj6z6g0541C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x2234cyj7090w3503_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w2234cyj70w693451_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v2215grsuw8ps34C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-22', '红棉双床套房', '套房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 20, 3.044522437723423, 8, '["前台服务", "卫生状况", "交通便利性"]'::jsonb, '前台服务', '卫生状况', '交通便利性', '未知酒店', '未知地点', '匿名', '第二次来，服务很好，环境清洁，前台小陈专业。酒店的地理位置便利就在淘金上盖。总体', '第二次来，服务很好，环境清洁，前台小陈专业。酒店的地理位置便利就在淘金上盖。总体很满意。团了套餐包早也送500餐券，等于午餐买一送一。房间升级了新装修的套房，感觉不错，就是有其他房间客人开门抽烟有点讨厌。', '2023-10-22', 5, '前台服务');
